-- Add `summary` column to Job. Stores an editorial 1–3 sentence TL;DR
-- generated by Claude Haiku at sync-time (src/lib/jobs/summarize.ts).
-- Populated on first ingest only — never re-summarized on update — so the
-- API cost is bounded by the rate of new listings, not by sync frequency.
--
-- Renders above the original HTML body in the Browse Jobs detail pane.
-- The original `content` column is the source of truth and is left
-- untouched; `summary` is purely an editorial layer.
--
-- Nullable + no default → metadata-only ALTER, safe under load. Rows ingested
-- before this migration land with summary = NULL; the next sync run picks
-- them up because the summarizer only fires when the existing row has a
-- null summary AND the job is new in that sync run (idempotent retry on
-- subsequent runs requires the row to be newly created — older rows stay
-- null until backfilled out-of-band).
ALTER TABLE "Job" ADD COLUMN "summary" TEXT;
